function activate(context) {
  context.ui.addToolbarButton({
    icon: 'puzzle',
    label: context.t('toolbar.label'),
    onClick: async function () {
      var mode = context.ai.getMode();
      context.ui.showNotification(context.t('notify.ai', { mode: mode }), 'info');
      try {
        var summary = context.debug.getSummary();
        context.ui.showNotification(
          context.t('notify.debug', {
            phase: summary.phase,
            active: String(summary.active),
          }),
          'info'
        );
      } catch (e) {
        context.ui.showNotification(String(e.message || e), 'error');
      }
    },
  });
}
